import math, subprocess, random

def fib(n):
    a,b=0,1
    for _ in range(n):
        a,b=b,(a+b)&0xffffffff
    return a

def ref(n):
    return fib(math.isqrt(n))

cases=[0,1,2,3,4,8,9,15,16,17,24,25,26,208,20000,65535,65536,65537,2**31-1,2**31,2**32-1]
cases += [random.Random(0).randrange(0,2**32) for _ in range(100)]
for n in cases:
    out = subprocess.check_output(['/app/sim', str(n)], text=True).strip()
    got = int(out)
    want = ref(n)
    if got != want:
        print('MISMATCH', n, got, want)
        raise SystemExit(1)
print('verified', len(cases), 'cases')
